import json, sys
baseline = json.load(open('baseline-packages.json'))
after = json.loads(sys.stdin.read())

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)
changes = []
for k in sorted(set(b) | set(a)):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    status = 'unchanged' if bv == av else 'CHANGED'
    print(f'{k[0]:15s} {k[1]:55s} {bv:10s} -> {av:10s}  {status}')
    if status == 'CHANGED':
        changes.append(k)
print(f'\nTotal changes: {len(changes)}')
" && dotnet package list --format json 2>/dev/null > after-cpm-packages.json", "description": "Compare baseline vs after", "initial_wait": 30}

